import SwiftUI
import SpriteKit

enum Palette {
    static let navy = Color(hex: 0x0A0F1E)
    static let card = Color(hex: 0x131C35)
    static let gold = Color(hex: 0xC9A84C)
    static let cream = Color(hex: 0xF5F0E8)
    static let fairway = Color(hex: 0x53D64C)
    static let sand = Color(hex: 0xF2D678)
    static let water = Color(hex: 0x35B6F2)
    static let danger = Color(hex: 0xE8574C)
}

enum SceneColors {
    static let navy = SKColor(hex: 0x0A0F1E)
    static let rough = SKColor(hex: 0x1E7D33)
    static let deepRough = SKColor(hex: 0x14571F)
    static let fairway = SKColor(hex: 0x53D64C)
    static let fringe = SKColor(hex: 0x6EE86A)
    static let green = SKColor(hex: 0x8CF77E)
    static let sand = SKColor(hex: 0xF2D678)
    static let water = SKColor(hex: 0x35B6F2)
    static let outline = SKColor(hex: 0x0B3D14)
    static let ball = SKColor(hex: 0xF5F0E8)
    static let gold = SKColor(hex: 0xC9A84C)
    static let flagRed = SKColor(hex: 0xE8574C)
}

extension Color {
    init(hex: UInt32) {
        self.init(
            .sRGB,
            red: Double((hex >> 16) & 0xFF) / 255,
            green: Double((hex >> 8) & 0xFF) / 255,
            blue: Double(hex & 0xFF) / 255,
            opacity: 1
        )
    }
}

extension SKColor {
    convenience init(hex: UInt32) {
        self.init(
            red: CGFloat((hex >> 16) & 0xFF) / 255,
            green: CGFloat((hex >> 8) & 0xFF) / 255,
            blue: CGFloat(hex & 0xFF) / 255,
            alpha: 1
        )
    }
}

// MARK: - Geometry helpers

extension CGPoint {
    func distance(to p: CGPoint) -> CGFloat {
        hypot(p.x - x, p.y - y)
    }
    static func + (l: CGPoint, r: CGVector) -> CGPoint {
        CGPoint(x: l.x + r.dx, y: l.y + r.dy)
    }
}

extension CGVector {
    init(from: CGPoint, to: CGPoint) {
        self.init(dx: to.x - from.x, dy: to.y - from.y)
    }
    var length: CGFloat { hypot(dx, dy) }
    var normalized: CGVector {
        let l = length
        guard l > 0.0001 else { return CGVector(dx: 0, dy: 1) }
        return CGVector(dx: dx / l, dy: dy / l)
    }
    /// Perpendicular pointing to the right of this vector.
    var perpendicularRight: CGVector { CGVector(dx: dy, dy: -dx) }
    static func * (v: CGVector, s: CGFloat) -> CGVector {
        CGVector(dx: v.dx * s, dy: v.dy * s)
    }
    static func + (l: CGVector, r: CGVector) -> CGVector {
        CGVector(dx: l.dx + r.dx, dy: l.dy + r.dy)
    }
    func dot(_ o: CGVector) -> CGFloat { dx * o.dx + dy * o.dy }
    func rotated(by radians: CGFloat) -> CGVector {
        CGVector(
            dx: dx * cos(radians) - dy * sin(radians),
            dy: dx * sin(radians) + dy * cos(radians)
        )
    }
}

