        emojiBurst(["💦", "🐟", "🌊"], at: p, count: 8, up: true)
        let ring = SKShapeNode(circleOfRadius: 6)
        ring.position = p
        ring.strokeColor = SceneColors.water
        ring.lineWidth = 4
        ring.zPosition = 15
        addChild(ring)
        ring.run(.sequence([
            .group([.scale(to: 4, duration: 0.5), .fadeOut(withDuration: 0.5)]),
            .removeFromParent()
        ]))
        ballNode.run(.fadeOut(withDuration: 0.25))
    }

    func celebrate(at p: CGPoint) {
        emojiBurst(["🎉", "🔥", "⭐️", "💰", "🎊"], at: p, count: 18, up: true)
    }

    func devastate(at p: CGPoint) {
        emojiBurst(["💀", "😭", "🤡"], at: p, count: 8, up: false)
    }

    private func emojiBurst(_ emojis: [String], at p: CGPoint, count: Int, up: Bool) {
        for _ in 0..<count {
            let label = SKLabelNode(text: emojis.randomElement())
            label.fontSize = CGFloat.random(in: 20...34)
            label.position = p
            label.zPosition = 20
            addChild(label)
            let dx = CGFloat.random(in: -90...90)
            let dy = up ? CGFloat.random(in: 60...170) : CGFloat.random(in: -150 ... -50)
            let move = SKAction.moveBy(x: dx, y: dy, duration: 0.9)
            move.timingMode = .easeOut
            label.run(.sequence([
                .group([move,
                        .rotate(byAngle: .random(in: -1.5...1.5), duration: 0.9),
                        .sequence([.wait(forDuration: 0.45), .fadeOut(withDuration: 0.45)])]),
                .removeFromParent()
            ]))
        }
    }

    private func landingPuff(at p: CGPoint) {
        let puff = SKShapeNode(circleOfRadius: 8)
        puff.position = p
        puff.fillColor = SKColor.white.withAlphaComponent(0.55)
        puff.strokeColor = .clear
        puff.zPosition = 8
        addChild(puff)
        puff.run(.sequence([
            .group([.scale(to: 2.6, duration: 0.35), .fadeOut(withDuration: 0.35)]),
            .removeFromParent()
        ]))
    }
}

